SELECT designer_name, designer_specialty
FROM designers
WHERE designer_id = 1;

SELECT body_type_name 
FROM body_types 
WHERE body_type_order <= (
  SELECT AVG(body_type_order) 
  FROM body_types
);

SELECT *
FROM admin_users
LIMIT 10;

SELECT body_type_name
FROM body_types
WHERE body_type_order > 2;
